@staticmethod
def _compute_idf(sentences):
    """
    Compute inverse document frequency for each term across all sentences.

    IDF is calculated as:

        idf(term) = log(N / df(term))

    where:
        N  = total number of sentences
        df = number of sentences containing the term
    """
    import math

    n_sentences = len(sentences)
    if n_sentences == 0:
        return {}

    # Document frequency for each term
    df = Counter()
    for sentence in sentences:
        df.update(set(sentence))

    return {
        term: math.log(n_sentences / freq)
        for term, freq in df.items()
        if freq > 0
    }

