def match_route(route, remaining_parts):
    # Route may be a dict with "path" and optional "children"
    route_path = route.get("path", "").strip("/")
    route_parts = [p for p in route_path.split("/") if p]

    # Match current route path segments
    if len(route_parts) > len(remaining_parts):
        return None

    for rp, pp in zip(route_parts, remaining_parts):
        if rp.startswith(":"):
            continue
        if rp != pp:
            return None

    # If fully matched and no more path parts, return this route
    if len(route_parts) == len(remaining_parts):
        return route

    # Otherwise, try children
    children = route.get("children", [])
    next_parts = remaining_parts[len(route_parts):]
    for child in children:
        found = match_route(child, next_parts)
        if found is not None:
            return found

    return None

