    @staticmethod
    def _fmt_structured(d):
        """Formats '{k1:v1, k2:v2}' => 'time=... pid=... k1=v1 k2=v2'

        Output is lexically sorted, *except* the time and pid always
        come first, to assist with human scanning of the data.
        """
        if d is None:
            d = {}

        # Ensure we don't mutate the caller's dict
        items = dict(d)

        # Always include time and pid first if present
        parts = []
        for key in ("time", "pid"):
            if key in items:
                parts.append(f"{key}={items.pop(key)}")

        # Then append the rest in lexical order
        for key in sorted(items.keys()):
            parts.append(f"{key}={items[key]}")

        return " ".join(parts)

