from functools import wraps

def decorator(func):
    # Resolve cache factory if needed
    _cache = cache() if callable(cache) else cache

    @wraps(func)
    def wrapper(*args, **kwargs):
        # Build cache key
        if key is not None:
            cache_key = key(func, *args, **kwargs)
        else:
            cache_key = args
            if kwargs:
                cache_key += (object(),)  # separator to avoid collisions
                cache_key += tuple(sorted(kwargs.items()))
            if typed:
                cache_key += tuple(type(v) for v in args)
                if kwargs:
                    cache_key += tuple(type(v) for _, v in sorted(kwargs.items()))
            if scoped:
                cache_key = (func,) + tuple(cache_key)

        try:
            return _cache[cache_key]
        except KeyError:
            result = func(*args, **kwargs)
            _cache[cache_key] = result
            return result

    return wrapper

return decorator

