def apply_jitter(value):
    if not jitter:
        return value
    # True behaves like 1.0
    j = 1.0 if jitter is True else float(jitter)
    if j >= 0:
        # value is the maximum; randomize between 0 and value
        return random.uniform(0.0, value * j)
    else:
        # value is the minimum; randomize between value and value * (1 - j)
        return random.uniform(value, value * (1.0 - j))

