def decorator(func):
    if not callable(func):
        raise TypeError("Expected a callable")

    # Try to inspect the callable's signature when possible
    try:
        import inspect
        sig = inspect.signature(func)
        params = sig.parameters.values()

        # Count required positional arguments
        required_positional = [
            p for p in params
            if p.kind in (p.POSITIONAL_ONLY, p.POSITIONAL_OR_KEYWORD)
            and p.default is p.empty
        ]

        # If it accepts *args, we can't strictly enforce an upper bound
        has_varargs = any(p.kind == p.VAR_POSITIONAL for p in params)

        if len(required_positional) > arity:
            raise TypeError(
                f"Callable requires at least {len(required_positional)} arguments, expected {arity}"
            )

        if not has_varargs:
            max_positional = [
                p for p in params
                if p.kind in (p.POSITIONAL_ONLY, p.POSITIONAL_OR_KEYWORD)
            ]
            if len(max_positional) < arity:
                raise TypeError(
                    f"Callable accepts at most {len(max_positional)} positional arguments, expected {arity}"
                )
    except (ValueError, TypeError):
        # Some builtins or callables may not have an inspectable signature.
        # In that case, just accept them as callable.
        pass

    return func

return decorator

from datetime import timedelta, date as _date

def _normalize_step(step):
    if isinstance(step, int):
        return timedelta(days=step)
    if isinstance(step, timedelta):
        return step
    if isinstance(step, tuple) and len(step) == 3:
        years, months, days = step
        return years, months, days
    raise TypeError(
        "step must be an int, datetime.timedelta, or a (year, month, day) tuple"
    )

def _add_ymd(d, y, m, dd):
    year = d.year + y
    month = d.month + m

    # Normalize month into 1..12 while carrying years
    year += (month - 1) // 12
    month = ((month - 1) % 12) + 1

    # Clamp day to last day of target month
    # (preserves common date arithmetic expectations)
    import calendar
    last_day = calendar.monthrange(year, month)[1]
    day = min(d.day, last_day)

    result = _date(year, month, day)
    if dd:
        result += timedelta(days=dd)
    return result

