if isinstance(step, tuple):
    # For Y/M/D stepping, compare dates directly each iteration.
    y, m, d = step
    forward = (y, m, d) >= (0, 0, 0)

    while True:
        if forward:
            if current > stop or (current == stop and not inclusive):
                break
        else:
            if current < stop or (current == stop and not inclusive):
                break

        yield current
        current = _add_ymd(current, y, m, d)
else:
    if step == timedelta(0):
        raise ValueError("step must not be zero")

    forward = step > timedelta(0)

    while True:
        if forward:
            if current > stop or (current == stop and not inclusive):
                break
        else:
            if current < stop or (current == stop and not inclusive):
                break

        yield current
        current = current + step

