@classmethod
def all_bootstraps(cls):
    '''Find all the available bootstraps and return them.'''
    import os
    import pkgutil
    import importlib

    bootstraps = []

    # Find the bootstraps package directory relative to this file.
    bootstrap_pkg = __name__.rsplit('.', 1)[0]
    try:
        pkg = importlib.import_module(bootstrap_pkg)
        pkg_path = pkg.__path__
    except Exception:
        return bootstraps

    # Import every module in the bootstraps package and collect Bootstrap subclasses.
    for _, modname, ispkg in pkgutil.iter_modules(pkg_path):
        if ispkg:
            continue
        try:
            module = importlib.import_module(f"{bootstrap_pkg}.{modname}")
        except Exception:
            continue

        for obj in module.__dict__.values():
            if (
                isinstance(obj, type)
                and issubclass(obj, cls)
                and obj is not cls
                and getattr(obj, "can_be_chosen_automatically", False)
            ):
                bootstraps.append(obj)

    # Remove duplicates while preserving order.
    seen = set()
    unique_bootstraps = []
    for bootstrap in bootstraps:
        if bootstrap not in seen:
            seen.add(bootstrap)
            unique_bootstraps.append(bootstrap)

    return unique_bootstraps

