@staticmethod
def _is_end_regex(word):
    """Returns `True` if `word` is the end of a regex."""
    if not word:
        return False

    # A regex is considered ended when it has a trailing unescaped `/`
    # and that slash is not the first character.
    if not word.endswith("/"):
        return False

    # Count trailing backslashes before the final slash to determine if it is escaped.
    i = len(word) - 2
    backslashes = 0
    while i >= 0 and word[i] == "\\":
        backslashes += 1
        i -= 1

    return backslashes % 2 == 0

