@classmethod
def ASYNC_WITH_LOOP(cls, loop):
    return functools.partial(cls._async_wrapper, loop)

@classmethod
def WEAK(cls, f):
    if not hasattr(f, "__call__"):
        raise TypeError("must be callable, got {!r}".format(f))
    return functools.partial(cls._weak_wrapper, f)

@classmethod
def AUTO_FUTURE(cls, future):
    if not isinstance(future, asyncio.Future):
        raise TypeError("must be asyncio.Future, got {!r}".format(future))
    return functools.partial(cls._future_wrapper, future)

@classmethod
def SPAWN_WITH_LOOP(cls, loop):
    return functools.partial(cls._spawn_wrapper, loop)

@classmethod
def SPAWN_WITH_LOOP(cls, loop):
    if loop is None:
        loop = asyncio.get_event_loop()

    def create_wrapper(f):
        if not hasattr(f, "__call__"):
            raise TypeError("must be callable, got {!r}".format(f))

        def wrapper(args, kwargs):
            coro = f(*args, **kwargs)
            task = asyncio.ensure_future(coro, loop=loop)

            def _done_callback(t):
                try:
                    result = t.result()
                except asyncio.CancelledError:
                    cls.logger.debug("spawned coroutine %r was cancelled", f)
                except Exception:
                    cls.logger.warning("spawned coroutine %r raised an exception",
                                       f, exc_info=True)
                else:
                    if result is not None:
                        cls.logger.info("spawned coroutine %r returned non-None value %r",
                                        f, result)

            task.add_done_callback(_done_callback)

        return wrapper

    return create_wrapper

