async def send_and_wait_for(xmlstream, send, wait_for,
                            timeout=None,
                            cb=None):
    """
    Send an XML stanza and wait for a matching response.

    :param xmlstream: XML stream object used to send data
    :param send: stanza to send
    :param wait_for: callable or matcher used to identify the expected reply
    :param timeout: optional timeout in seconds
    :param cb: optional callback invoked with the received stanza before matching
    :return: the stanza that matched wait_for
    """
    loop = asyncio.get_event_loop()
    fut = loop.create_future()

    def _handler(stanza):
        try:
            if cb is not None:
                cb(stanza)
            if wait_for(stanza):
                if not fut.done():
                    fut.set_result(stanza)
        except Exception as e:
            if not fut.done():
                fut.set_exception(e)

    # Register temporary handler
    xmlstream.add_handler(_handler)

    try:
        await xmlstream.send(send)

        if timeout is not None:
            return await asyncio.wait_for(fut, timeout)
        return await fut
    finally:
        # Best-effort cleanup if the stream supports removing handlers
        if hasattr(xmlstream, "remove_handler"):
            try:
                xmlstream.remove_handler(_handler)
            except Exception:
                pass

