import hashlib

# XEP-0390: sort forms by FORM_TYPE field value, then serialize each form
# in a canonical way and hash the resulting byte stream.
forms = list(exts)

def _form_type_value(form):
    for field in getattr(form, "fields", []):
        var = getattr(field, "var", None)
        values = getattr(field, "values", None)
        if var == "FORM_TYPE" and values:
            return values[0]
    return ""

forms.sort(key=_form_type_value)

parts = []
for form in forms:
    # Canonical representation: include FORM_TYPE first, then all other
    # fields sorted by var name.
    fields = list(getattr(form, "fields", []))

    def _field_key(field):
        return getattr(field, "var", "")

    fields.sort(key=_field_key)

    for field in fields:
        var = getattr(field, "var", "")
        values = getattr(field, "values", []) or []
        parts.append(var.encode("utf-8"))
        for value in values:
            parts.append(b"\x1f")
            parts.append(str(value).encode("utf-8"))
        parts.append(b"\x1e")

return hashlib.sha1(b"".join(parts)).digest()

