    results = []
    if not no_polychords:
        results.extend(determine_polychords(chord, shorthand))

    # Also try to identify the chord as an extended chord by slicing from
    # the front; this mirrors the behavior of the specialized helpers.
    if len(chord) > 7:
        # Try all supported sub-lengths from 7 down to 3.
        for n in range(min(len(chord), 7), 2, -1):
