class Introspector:
    def __init__(self):
        self._refs = {}
        self._categories = {}
        self._counter = 0

    def add(self, intr):
        category = self._categories.setdefault(intr.category_name, {})
        category[intr.discriminator] = intr
        category[intr.discriminator_hash] = intr
        intr.order = self._counter
        self._counter += 1

    def get(self, category_name, discriminator, default=None):
        category = self._categories.setdefault(category_name, {})
        intr = category.get(discriminator, default)
        return intr

    def get_category(self, category_name, default=None, sort_key=None):
        category = self._categories.get(category_name)
        if category is None:
            return default

        # Deduplicate entries because each introspection object is stored
        # under both its discriminator and discriminator_hash.
        items = list({id(v): v for v in category.values()}.values())

        if sort_key is None:
            sort_key = lambda intr: getattr(intr, "order", 0)

        return sorted(items, key=sort_key)

    constraint: Union[Index, Constraint], dialect: Optional[Dialect]
) -> Optional[str]:
    name = constraint.name

    if name is None:
        return None

    # SQLAlchemy naming convention tokens may produce a "final" name only when
    # rendered against a dialect. If no dialect is present, return the raw name.
    if dialect is None:
        return name

    # If the name is already a plain string, return it directly.
    if isinstance(name, str):
        return name

    # For SQLAlchemy's special naming objects / quoted names, coerce to string.
    try:
        return str(name)
    except Exception:
        return None

