@staticmethod
def power_method(matrix, epsilon):
    transposed = matrix.T
    n = matrix.shape[0]
    p = numpy.full(n, 1.0 / n)

    while True:
        new_p = transposed.dot(p)
        if numpy.abs(new_p - p).sum() < epsilon:
            return new_p
        p = new_p

