@classmethod
def load(cls, dirname=None, locales=None, domain=DEFAULT_DOMAIN):
    """Load translations from the given directory.

    :param dirname: the directory containing the ``MO`` files
    :param locales: the list of locales in order of preference (items in
                    this list can be either `Locale` objects or locale
                    strings)
    :param domain: the message domain
    :return: the loaded catalog, or a ``NullTranslations`` instance if no
             matching translations were found
    :rtype: `Translations`
    """
    if dirname is None or locales is None:
        return gettext.NullTranslations()

    if isinstance(locales, str):
        locales = [locales]

    # Normalize locale objects to strings
    normalized_locales = []
    for locale in locales:
        normalized_locales.append(str(locale))

    # Try locales in order of preference, including fallbacks like
    # "en_US" -> "en"
    candidates = []
    for locale in normalized_locales:
        parts = locale.split('_')
        for i in range(len(parts), 0, -1):
            candidate = '_'.join(parts[:i])
            if candidate not in candidates:
                candidates.append(candidate)

    for locale in candidates:
        mo_path = os.path.join(dirname, locale, 'LC_MESSAGES', '%s.mo' % domain)
        if os.path.exists(mo_path):
            with open(mo_path, 'rb') as fp:
                return cls(fp, domain=domain)

    return gettext.NullTranslations()

