@staticmethod
def merge(files, accumulate=True):
    """Merge metrics from given mmap files.

    By default, histograms are accumulated, as per prometheus wire format.
    But if writing the merged data back to mmap files, use
    accumulate=False to avoid compound accumulation.
    """
    from collections import defaultdict

    metrics = defaultdict(lambda: defaultdict(float))
    histograms = defaultdict(lambda: defaultdict(float))
    summaries = defaultdict(lambda: defaultdict(float))

    for f in files:
        with open(f, 'rb') as fd:
            data = fd.read()

        # Each file contains a sequence of JSON-encoded metric records.
        # Records are separated by newlines.
        for line in data.splitlines():
            if not line:
                continue
            metric = json.loads(line.decode('utf-8'))

            name = metric['name']
            mtype = metric['type']
            labels = tuple(sorted(metric.get('labels', {}).items()))
            value = metric.get('value', 0.0)

            if mtype == 'counter' or mtype == 'gauge':
                metrics[(name, mtype)][labels] += value

            elif mtype == 'histogram':
                # Histogram records are expected to contain:
                #   - buckets: dict of upper_bound -> count
                #   - sum: total sum
                #   - count: total count
                key = (name, mtype)
                hist = metric.get('buckets', {})
                for bucket, count in hist.items():
                    histograms[(key, bucket)][labels] += count
                histograms[(key, 'sum')][labels] += metric.get('sum', 0.0)
                histograms[(key, 'count')][labels] += metric.get('count', 0.0)

            elif mtype == 'summary':
                # Summary records are expected to contain:
                #   - quantiles: dict of quantile -> value
                #   - sum: total sum
                #   - count: total count
                key = (name, mtype)
                q = metric.get('quantiles', {})
                for quantile, qv in q.items():
                    summaries[(key, quantile)][labels] += qv
                summaries[(key, 'sum')][labels] += metric.get('sum', 0.0)
                summaries[(key, 'count')][labels] += metric.get('count', 0.0)

    merged = []

    for (name, mtype), by_labels in metrics.items():
        for labels, value in by_labels.items():
            merged.append({
                'name': name,
                'type': mtype,
                'labels': dict(labels),
                'value': value,
            })

    # Reconstruct histogram records
    histogram_keys = defaultdict(lambda: {'buckets': {}, 'sum': 0.0, 'count': 0.0})
    for (key, part), by_labels in histograms.items():
        (name, mtype) = key
        for labels, value in by_labels.items():
            rec = histogram_keys[(name, labels)]
            if part == 'sum':
                rec['sum'] += value
            elif part == 'count':
                rec['count'] += value
            else:
                rec['buckets'][part] = rec['buckets'].get(part, 0.0) + value

    for (name, labels), rec in histogram_keys.items():
        if accumulate:
            # Accumulate buckets in ascending order.
            buckets = {}
            running = 0.0
            for b in sorted(rec['buckets'], key=lambda x: float(x)):
                running += rec['buckets'][b]
                buckets[b] = running
            rec['buckets'] = buckets
        merged.append({
            'name': name,
            'type': 'histogram',
            'labels': dict(labels),
            'buckets': rec['buckets'],
            'sum': rec['sum'],
            'count': rec['count'],
        })

    # Reconstruct summary records
    summary_keys = defaultdict(lambda: {'quantiles': {}, 'sum': 0.0, 'count': 0.0})
    for (key, part), by_labels in summaries.items():
        (name, mtype) = key
        for labels, value in by_labels.items():
            rec = summary_keys[(name, labels)]
            if part == 'sum':
                rec['sum'] += value
            elif part == 'count':
                rec['count'] += value
            else:
                rec['quantiles'][part] = rec['quantiles'].get(part, 0.0) + value

    for (name, labels), rec in summary_keys.items():
        merged.append({
            'name': name,
            'type': 'summary',
            'labels': dict(labels),
            'quantiles': rec['quantiles'],
            'sum': rec['sum'],
            'count': rec['count'],
        })

    return merged

