@classmethod
def from_constraint(cls, constraint: Constraint) -> DropConstraintOp:
    schema = getattr(constraint.table, "schema", None)
    table_name = constraint.table.name

    # Try to preserve the constraint name in a SQLAlchemy-compatible way.
    constraint_name = getattr(constraint, "name", None)

    # Determine the Alembic-style constraint type.
    if isinstance(constraint, ForeignKeyConstraint):
        type_ = "foreignkey"
    elif isinstance(constraint, PrimaryKeyConstraint):
        type_ = "primary"
    elif isinstance(constraint, UniqueConstraint):
        type_ = "unique"
    elif isinstance(constraint, CheckConstraint):
        type_ = "check"
    else:
        type_ = constraint.__visit_name__

    return cls(
        constraint_name=constraint_name,
        table_name=table_name,
        type_=type_,
        schema=schema,
    )

