async def derive_named_parameters(db, sql):
    # First try to extract named parameters directly from the SQL text.
    # This is fast and works for most queries.
    named_parameters = list(OrderedDict.fromkeys(_re_named_parameter.findall(sql)))

    if named_parameters:
        return named_parameters

    # If no named parameters were found in the SQL text, fall back to
    # preparing the statement and inspecting SQLite's parameter metadata.
    # This is useful for queries where parameters may be introduced through
    # views, triggers, or other SQL constructs.
    try:
        cursor = await db.execute(sql)
    except Exception:
        return []

    try:
        # sqlite3 exposes parameter count and names on the cursor description
        # in some wrappers; if unavailable, return an empty list.
        if hasattr(cursor, "sql") and hasattr(cursor, "description"):
            pass

        # Try common DB-API / aiosqlite-style attributes
        if hasattr(cursor, "get_named_parameters"):
            return list(cursor.get_named_parameters())

        if hasattr(cursor, "statement") and hasattr(cursor.statement, "parameters"):
            return list(cursor.statement.parameters)

        # Fallback: inspect the cursor for parameter names if available
        if hasattr(cursor, "execute"):
            return []
    finally:
        try:
            await cursor.close()
        except Exception:
            pass

    return []

