@property
def precedence(self):
    """
    Return a precedence level from 0-3 for the media type given how specific it is.
    """
    # Most specific: both main and sub types are concrete
    if self.main_type != '*' and self.sub_type != '*':
        return 3

    # One wildcard: either main or sub type is wildcard, but not both
    if self.main_type == '*' and self.sub_type == '*':
        return 0

    return 1 if self.main_type == '*' or self.sub_type == '*' else 2

