class LengthReader(object):
    def __init__(self, unreader, length):
        self.unreader = unreader
        self.length = length

    def read(self, size):
        if self.length <= 0:
            return b""

        if size is None or size < 0:
            size = self.length
        else:
            size = min(size, self.length)

        data = self.unreader.read(size)
        if data is None:
            data = b""

        self.length -= len(data)
        return data

