@classmethod
def from_page_data(cls, tree_conf: TreeConf, data: bytes,
                   page: int=None) -> 'Node':
    """Create the appropriate node type from raw page data."""
    assert len(data) == tree_conf.page_size

    node_type = data[0]

    if node_type == 1:
        return LonelyRootNode(tree_conf, data=data, page=page)
    elif node_type == 2:
        return RootNode(tree_conf, data=data, page=page)
    elif node_type == 3:
        return InternalNode(tree_conf, data=data, page=page)
    elif node_type == 4:
        return LeafNode(tree_conf, data=data, page=page)

    raise ValueError('Unknown node type: {}'.format(node_type))

class Introspector:
    def __init__(self):
        self._refs = {}
        self._categories = {}
        self._counter = 0

    def add(self, intr):
        if intr is None:
            return None

        # Reuse existing reference if we've already seen this object
        obj_id = id(intr)
        if obj_id in self._refs:
            return self._refs[obj_id]

        # Assign a new reference id
        ref = self._counter
        self._counter += 1
        self._refs[obj_id] = ref

        # Categorize by type name
        category = type(intr).__name__
        self._categories.setdefault(category, []).append(intr)

        return ref

