@contextlib.contextmanager
def assertLoopErrorHandlerCalled(self, msg_re: str):
    """
    Assert that the event loop's exception handler is called with a
    message matching ``msg_re`` while the context is active.
    """
    import re

    old_handler = self.loop.get_exception_handler()
    called = []

    def handler(loop, context):
        called.append(context)
        if old_handler is not None:
            old_handler(loop, context)

    self.loop.set_exception_handler(handler)
    try:
        yield
    finally:
        self.loop.set_exception_handler(old_handler)

        if not called:
            raise AssertionError(
                f'loop exception handler was not called; expected message '
                f'matching {msg_re!r}'
            )

        if not any(re.search(msg_re, str(ctx.get('message', ''))) for ctx in called):
            messages = [str(ctx.get('message', '')) for ctx in called]
            raise AssertionError(
                f'loop exception handler was called, but none of the '
                f'messages matched {msg_re!r}: {messages!r}'
            )

