class IntStreamer(object):

    @classmethod
    def int_from_script_bytes(class_, s, require_minimal=False):
        if not s:
            return 0

        # Bitcoin script numbers are little-endian signed integers.
        # The most significant byte's top bit is the sign bit.
        v = 0
        for i, b in enumerate(s):
            v |= b << (8 * i)

        # If the sign bit is set, clear it and negate the result.
        if s[-1] & 0x80:
            v &= ~(0x80 << (8 * (len(s) - 1)))
            v = -v

        return v

