class PrevalenceCounter:
    def __init__(self):
        self.keyword_counts = defaultdict(int)
        self.name_counts = defaultdict(int)

    def update(self, text):
        if not text:
            return

        # Count words in a case-insensitive way
        words = text.split()
        for word in words:
            cleaned = word.strip(".,!?;:\"'()[]{}<>").lower()
            if not cleaned:
                continue

            # Heuristic: treat capitalized words as names, otherwise keywords
            if word[:1].isupper():
                self.name_counts[cleaned] += 1
            else:
                self.keyword_counts[cleaned] += 1

