@classmethod
def to_payload(
    cls,
    batch: ext.NpNDArray,
    batch_dim: int,
) -> Payload:
    # skip 0-dimensional array
    if batch.ndim == 0:
        data = pickle.dumps(batch, protocol=5)
        return cls.create_payload(data, batch_size=1)

    # If the batch is contiguous along the batch dimension, serialize with PEP 574
    # so large array buffers can be transferred out-of-band.
    if batch.flags.c_contiguous or batch.flags.f_contiguous:
        main_bytes, buffer_bytes, indices = pep574_dumps(batch)
        meta = {"indices": indices}
        return cls.create_payload(
            main_bytes + buffer_bytes,
            batch_size=batch.shape[batch_dim],
            meta=meta,
        )

    # Fallback for non-contiguous arrays
    data = pickle.dumps(batch, protocol=5)
    return cls.create_payload(data, batch_size=batch.shape[batch_dim])

