@cached_property
def document(self):
    paragraphs = []
    current_lines = []

    def flush_paragraph(lines):
        if not lines:
            return

        # Remove leading/trailing empty lines inside a paragraph block
        while lines and not lines[0].strip():
            lines.pop(0)
        while lines and not lines[-1].strip():
            lines.pop()

        if not lines:
            return

        # Detect heading: a single line in ALL UPPER CASE
        headings = []
        if len(lines) >= 1:
            first_line = lines[0].strip()
            if first_line and first_line == first_line.upper():
                headings.append(first_line)
                lines = lines[1:]

        text = "\n".join(lines).strip()
        if not text and not headings:
            return

        paragraphs.append(
            type("Paragraph", (), {
                "headings": [type("Heading", (), {"words": self.tokenize_words(h)}) for h in headings],
                "text": text,
                "sentences": self.tokenize_sentences(text),
            })()
        )

    for line in self._text.splitlines():
        if line.strip():
            current_lines.append(line)
        else:
            flush_paragraph(current_lines)
            current_lines = []

    flush_paragraph(current_lines)

    return type("Document", (), {"paragraphs": paragraphs})()

