@classmethod
def from_spec(cls, spec: t.Any) -> float:
    """
    Convert spec to CpuResource.

    spec can be a float, int or string.
    - 1.0 -> 1.0
    - 1 -> 1.0
    - "1" -> 1.0
    - "10m" -> 0.01
    """
    if isinstance(spec, (int, float)):
        return float(spec)

    if isinstance(spec, str):
        s = spec.strip().lower()
        if s.endswith("m"):
            try:
                return float(s[:-1]) / 1000.0
            except ValueError as e:
                raise BentoMLConfigException(f"Invalid cpu resource specification: {spec!r}") from e
        try:
            return float(s)
        except ValueError as e:
            raise BentoMLConfigException(f"Invalid cpu resource specification: {spec!r}") from e

    raise BentoMLConfigException(
        f"Invalid cpu resource specification: {spec!r}. "
        "Expected int, float, or string."
    )

