@classmethod
def get_distrust_timeline(
    cls, verified_certificate_chain: List[Certificate]
) -> Optional[SymantecDistrustTimelineEnum]:
    # No chain or only leaf certificate: cannot determine Symantec distrust status.
    if not verified_certificate_chain or len(verified_certificate_chain) < 2:
        return None

    # Check the chain for any Symantec root / managed CA key.
    # The leaf certificate is excluded; we only care about CA certificates.
    for certificate in verified_certificate_chain[1:]:
        pubkey_sha256 = binascii.hexlify(get_public_key_sha256(certificate)).decode("ascii")

        # Whitelisted keys were exempt from the March 2018 distrust.
        if pubkey_sha256 in cls._CA_KEYS_WHITELIST:
            continue

        # Blacklisted keys were distrusted starting in March 2018.
        if pubkey_sha256 in cls._CA_KEYS_BLACKLIST:
            return SymantecDistrustTimelineEnum.MARCH_2018

    # If no blacklisted CA key was found, but the chain contains a Symantec CA
    # that is not whitelisted, it was distrusted in September 2018.
    for certificate in verified_certificate_chain[1:]:
        pubkey_sha256 = binascii.hexlify(get_public_key_sha256(certificate)).decode("ascii")
        if pubkey_sha256 not in cls._CA_KEYS_WHITELIST:
            return SymantecDistrustTimelineEnum.SEPTEMBER_2018

    return None

