class CommandLineServerStringParser:
    """Utility class to parse a 'host:port{ip}' string taken from the command line into a valid (host,ip, port) tuple.
    Supports IPV6 addresses.
    """

    SERVER_STRING_ERROR_BAD_PORT = "Not a valid host:port"

    @classmethod
    def parse_server_string(cls, server_str: str) -> Tuple[str, Optional[str], Optional[int]]:
        # Extract ip from target
        ip = None
        if "{" in server_str and server_str.endswith("}"):
            server_str, ip = server_str.rsplit("{", 1)
            ip = ip[:-1]  # strip trailing "}"

        # Parse host and port
        host = server_str
        port = None

        if host.startswith("["):
            # IPv6 in bracket form: [::1]:8080
            end = host.find("]")
            if end == -1:
                raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)
            raw_host = host[1:end]
            remainder = host[end + 1 :]
            if remainder:
                if not remainder.startswith(":"):
                    raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)
                port_str = remainder[1:]
                if not port_str:
                    raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)
                try:
                    port = int(port_str)
                except ValueError:
                    raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)
            host = raw_host
        else:
            # Split on the last colon to support IPv6 without brackets only when no port is present
            if ":" in host:
                left, right = host.rsplit(":", 1)
                # If right is numeric, treat as port; otherwise keep as host (likely IPv6 literal)
                if right.isdigit():
                    host = left
                    try:
                        port = int(right)
                    except ValueError:
                        raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)

        return host, ip, port

