class Unreader(object):
    def __init__(self):
        self.buf = io.BytesIO()

    def chunk(self):
        raise NotImplementedError()

    def read(self, size=None):
        # Read all available data if size is not specified
        if size is None:
            chunks = [self.buf.read()]
            while True:
                data = self.chunk()
                if not data:
                    break
                chunks.append(data)
            return b"".join(chunks)

        # Read exactly `size` bytes if possible
        out = bytearray()

        # First consume from the internal buffer
        remaining = size - len(out)
        if remaining > 0:
            out.extend(self.buf.read(remaining))

        # Then keep pulling chunks until enough data is gathered or exhausted
        while len(out) < size:
            data = self.chunk()
            if not data:
                break
            needed = size - len(out)
            out.extend(data[:needed])

            # If we got more than needed, store the remainder back in the buffer
            if len(data) > needed:
                self.buf = io.BytesIO(data[needed:])
                break

        return bytes(out)

