    kwargs: dict[str, Any],
    state: Optional["State"] = None,
    host: Optional["Host"] = None,
    keys_to_check=None,
) -> Tuple[AllArguments, list[str]]:
    """
    Pop and return operation global keyword arguments, in preferred order:

    + From the current context (a direct @operator or @deploy function being called)
    + From any current @deploy context (deploy kwargs)
    + From the host data variables
    + From the config variables

    Note this function is only called directly in the @operation & @deploy decorator
    wrappers which the user should pass global arguments prefixed "_". This is to
    avoid any clashes with operation and deploy functions both internal and third
    party.

    This is a bit strange because internally pyinfra uses non-_-prefixed arguments,
    and this function is responsible for the translation between the two.

    TODO: is this weird-ness acceptable? Is it worth updating internal use to _prefix?
    """
    if keys_to_check is None:
        keys_to_check = []

    # Start with any current context arguments.
    global_arguments: AllArguments = {}

    # Current @operation context
    if host is not None and getattr(host, "current_op_global_arguments", None):
        global_arguments.update(host.current_op_global_arguments)

    # Current @deploy context
    if host is not None and getattr(host, "current_deploy_kwargs", None):
        global_arguments.update(host.current_deploy_kwargs)

    # Host data variables
    if host is not None:
        host_data = getattr(host, "data", None)
        if host_data is not None:
            for key in keys_to_check:
                if key in kwargs:
                    continue
                try:
                    value = host_data[key]
                except Exception:
                    continue
                if value is not None:
                    global_arguments[key] = value

    # Config variables
    if state is not None and getattr(state, "config", None) is not None:
        config = state.config
        for key in keys_to_check:
            if key in kwargs or key in global_arguments:
                continue
            if hasattr(config, key):
                value = getattr(config, key)
                if value is not None:
                    global_arguments[key] = value

    # Pop any explicitly passed global args from kwargs, translating _foo -> foo
    popped_keys: list[str] = []
    for key in list(kwargs.keys()):
        if not key.startswith("_"):
            continue

        value = kwargs.pop(key)
        translated_key = key[1:]
        global_arguments[translated_key] = value
        popped_keys.append(translated_key)

    return global_arguments, popped_keys

