# Expected semitones for major/perfect intervals
base = {
    1: 0,  # perfect unison
    2: 2,  # major second
    3: 4,  # major third
    4: 5,  # perfect fourth
    5: 7,  # perfect fifth
    6: 9,  # major sixth
    7: 11, # major seventh
    8: 12, # perfect octave
}

# Interval quality naming
if interval_number in (1, 4, 5, 8):
    # Perfect-type intervals
    if semitones == base[interval_number]:
        quality = "perfect"
        short = "P"
    elif semitones == base[interval_number] + 1:
        quality = "augmented"
        short = "A"
    elif semitones == base[interval_number] - 1:
        quality = "diminished"
        short = "d"
    else:
        # Handle double augmented/diminished and beyond
        diff = semitones - base[interval_number]
        if diff > 0:
            quality = "augmented" * diff
            short = "A" * diff
        else:
            quality = "diminished" * (-diff)
            short = "d" * (-diff)
else:
    # Major/minor-type intervals
    if semitones == base[interval_number]:
        quality = "major"
        short = "M"
    elif semitones == base[interval_number] - 1:
        quality = "minor"
        short = "m"
    elif semitones > base[interval_number]:
        quality = "augmented" * (semitones - base[interval_number])
        short = "A" * (semitones - base[interval_number])
    else:
        quality = "diminished" * (base[interval_number] - semitones - 1)
        short = "d" * (base[interval_number] - semitones)

