class Arch:

    command_prefix = None
    '''The prefix for NDK commands such as gcc.'''

    arch = ""
    '''Name of the arch such as: `armeabi-v7a`, `arm64-v8a`, `x86`...'''

    arch_cflags = []
    '''Specific arch `cflags`, expect to be overwrote in subclass if needed.'''

    common_cflags = [
        '-target {target}',
        '-fomit-frame-pointer'
    ]

    common_cppflags = [
        '-DANDROID',
        '-I{ctx.ndk.sysroot_include_dir}',
        '-I{python_includes}',
    ]

    common_ldflags = ['-L{ctx_libs_dir}']

    common_ldlibs = ['-lm']

    common_ldshared = [
        '-pthread',
        '-shared',
        '-Wl,-O1',
        '-Wl,-Bsymbolic-functions',
    ]

    def __init__(self, ctx):
        self.ctx = ctx

        # Allows injecting additional linker paths used by any recipe.
        # This can also be modified by recipes (like the librt recipe)
        # to make sure that some sort of global resource is available &
        # linked for all others.
        self.extra_global_link_paths = []

    def __str__(self):
        return self.arch

    @property
    def ndk_lib_dir(self):
        return join(self.ctx.ndk.sysroot_lib_dir, self.command_prefix)

    @property
    def ndk_lib_dir_versioned(self):
        return join(self.ndk_lib_dir, str(self.ctx.ndk_api))

    @property
    def include_dirs(self):
        return [
            "{}/{}".format(
                self.ctx.include_dir,
                d.format(arch=self))
            for d in self.ctx.include_dirs]

    @property
    def target(self):
        # As of NDK r19, the toolchains installed by default with the
        # NDK may be used in-place. The make_standalone_toolchain.py script
        # is no longer needed for interfacing with arbitrary build systems.
        # See: https://developer.android.com/ndk/guides/other_build_systems
        return self.command_prefix

    @property
    def python_includes(self):
        return " ".join(self.include_dirs)

    @property
    def ctx_libs_dir(self):
        return self.ctx.libs_dir

    @property
    def cflags(self):
        return " ".join(
            [f.format(target=self.target, ctx=self.ctx, python_includes=self.python_includes,
                      ctx_libs_dir=self.ctx_libs_dir, arch=self)]
            for f in (self.common_cflags + self.arch_cflags)
        )

    @property
    def cppflags(self):
        return " ".join(
            [f.format(target=self.target, ctx=self.ctx, python_includes=self.python_includes,
                      ctx_libs_dir=self.ctx_libs_dir, arch=self)]
            for f in self.common_cppflags
        )

    @property
    def ldflags(self):
        flags = list(self.common_ldflags)
        flags.extend(self.extra_global_link_paths)
        return " ".join(
            [f.format(target=self.target, ctx=self.ctx, python_includes=self.python_includes,
                      ctx_libs_dir=self.ctx_libs_dir, arch=self)]
            for f in flags
        )

    @property
    def ldlibs(self):
        return " ".join(self.common_ldlibs)

    @property
    def ldshared(self):
        return " ".join(
            [f.format(target=self.target, ctx=self.ctx, python_includes=self.python_includes,
                      ctx_libs_dir=self.ctx_libs_dir, arch=self)]
            for f in self.common_ldshared
        )

