# calc target position from self.pos, pos and offset
if self.handle is None:
    raise IOError('seek on closed handle')

if offset == io.SEEK_SET:
    target = pos
elif offset == io.SEEK_CUR:
    target = self.pos + pos
elif offset == io.SEEK_END:
    target = self.size + pos
else:
    raise ValueError('invalid seek mode: {0}'.format(offset))

if target < 0:
    raise IOError('negative seek position {0}'.format(target))

# If seeking backwards or beyond current stream position, reopen and skip.
if target < self.pos:
    self.reset()
elif target > self.pos:
    # skip forward by reading/discarding
    remaining = target - self.pos
    while remaining > 0:
        chunk = self.handle.read(min(self.CHUNK_SIZE, remaining))
        if not chunk:
            break
        self.pos += len(chunk)
        remaining -= len(chunk)

return self.pos

