def _compute_ratings(self, sentences):
    all_content_words = self._get_all_content_words_in_doc(sentences)
    word_freq = self._compute_word_freq(all_content_words)

    if not word_freq:
        return {}

    total = float(sum(word_freq.values()))
    word_prob = {w: freq / total for w, freq in word_freq.items()}

    ratings = {}
    for sentence in sentences:
        content_words = self._get_content_words_in_sentence(sentence)
        if not content_words:
            ratings[sentence] = 0.0
            continue

        score = 1.0
        for w in content_words:
            score *= word_prob.get(w, 0.0)

        ratings[sentence] = score / len(content_words)

        # Update word probabilities after selecting/scoring sentence
        # (SumBasic-style frequency adjustment)
        for w in content_words:
            if w in word_prob:
                word_prob[w] = word_prob[w] ** 2

    return ratings

