async def facet_results(self):
    facet_size = self.get_facet_size()
    columns = await self.get_columns(self.sql, self.params)
    if not columns:
        return [], False

    # Use the first column that looks like a date facet target
    facet_column = None
    for column in columns:
        if column == self.request.args.get("_facet_date"):
            facet_column = column
            break

    if facet_column is None:
        return [], False

    facet_sql = """
        select
            date({column}) as value,
            count(*) as count
        from (
            {sql}
        )
        where {column} is not null
        group by date({column})
        order by count(*) desc, value
        limit {limit}
    """.format(
        column=escape_sqlite(facet_column),
        sql=self.sql,
        limit=facet_size + 1,
    )

    try:
        results = await self.ds.execute(
            self.database,
            facet_sql,
            self.params,
            truncate=False,
            custom_time_limit=self.ds.setting("facet_time_limit_ms"),
            log_sql_errors=False,
        )
    except (QueryInterrupted, sqlite3.OperationalError):
        return [], True

    timed_out = len(results.rows) > facet_size
    rows = results.rows[:facet_size]

    return (
        [
            {
                "value": row[0],
                "label": row[0] or "(none)",
                "count": row[1],
                "toggle_url": self.ds.absolute_url(
                    self.request,
                    self.ds.urls.path(
                        path_with_removed_args(self.request, {"_facet_date"})
                    ),
                ),
            }
            for row in rows
        ],
        timed_out,
    )

