class Float(ConfigValue):
    """Float value."""

    def __init__(self, minimum=None, maximum=None, optional=False):
        self._required = not optional
        self._minimum = minimum
        self._maximum = maximum

    def deserialize(self, value):
        if value is None:
            if self._required:
                raise ValueError("Value is required")
            return None

        try:
            value = float(value)
        except (TypeError, ValueError):
            raise ValueError("Invalid float value: %r" % value)

        if self._minimum is not None and value < self._minimum:
            raise ValueError(
                "Value %r is less than minimum %r" % (value, self._minimum)
            )

        if self._maximum is not None and value > self._maximum:
            raise ValueError(
                "Value %r is greater than maximum %r" % (value, self._maximum)
            )

        return value

